content.query:
// Treat the workbook parameter as a JSON array (dynamic)
let p = dynamic({SelectPaasType});
let use_all = array_length(p) == 0 or 'All' in (p) or 'all' in (p);
let latestBatch = toscalar(MonitoredPaaSTable_CL | summarize max(TimeGenerated));
MonitoredPaaSTable_CL
| where TimeGenerated == latestBatch
| summarize arg_max(TimeGenerated, *) by Resource, resourceGroup, resourcetype, location, resourcekind, subscriptionId
| where use_all or resourcetype in~ (p)         // `in~` works with dynamic arrays too
| project Resource, resourceGroup, type=resourcetype, location, resourcekind, subscriptionId
| where isnotempty(location)

